function pD(s){return new Date(s).getTime()}
function avg(a){return a.length?a.reduce((s,v)=>s+v,0)/a.length:0}
function computeMonthly(d){const b={};d.forEach(([dt,v])=>{if(v==null)return;const t=new Date(dt);const k=`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,'0')}`;if(!b[k])b[k]=[];b[k].push(v)});return Object.entries(b).map(([k,v])=>({month:k,mean:avg(v)})).sort((a,b)=>a.month.localeCompare(b.month))}

// =============================================
// CHART — actual + expected overlay
// =============================================
function CompChart({actual,expected,actualColor,expectedColor,actualLabel,expectedLabel,title,yMin,yMax,monthly}){
  const[hover,setHover]=useState(null);
  const p={top:30,right:16,bottom:38,left:50};const w=800,h=280;const cw=w-p.left-p.right,ch=h-p.top-p.bottom;
  const tMin=pD("Jan 1, 2019"),tMax=pD("Apr 15, 2026"),tR=tMax-tMin;
  const toX=t=>p.left+((t-tMin)/tR)*cw;
  const toY=v=>p.top+ch-((v-yMin)/(yMax-yMin))*ch;

  // Actual points
  let aPts;
  if(monthly){
    const m=computeMonthly(actual);
    aPts=m.map(q=>({x:toX(new Date(q.month+'-15').getTime()),y:toY(q.mean),v:q.mean,label:q.month}));
  } else {
    aPts=actual.filter(d=>d[1]!=null).map(([d,v])=>({x:toX(pD(d)),y:toY(v),v,label:d}));
  }
  // Expected points
  const ePts=expected.map(([d,v])=>({x:toX(pD(d)),y:toY(v),v,label:d}));

  const mkLine=pts=>pts.map((q,i)=>`${i===0?'M':'L'}${q.x.toFixed(1)},${q.y.toFixed(1)}`).join(' ');
  const mkArea=pts=>mkLine(pts)+` L${pts[pts.length-1].x.toFixed(1)},${p.top+ch} L${pts[0].x.toFixed(1)},${p.top+ch} Z`;

  const years=[2019,2020,2021,2022,2023,2024,2025,2026];
  const yTicks=[];for(let v=yMin;v<=yMax+0.001;v+=(yMax-yMin)/4)yTicks.push(v);

  // Phase labels for expected
  const phases=[
    {x1:"Jun 1, 2020",x2:"Jun 1, 2021",label:"Sewage stopped",y:22},
    {x1:"Sep 1, 2021",x2:"Jan 1, 2023",label:"Desilting",y:22},
    {x1:"Jun 1, 2023",x2:"Dec 1, 2024",label:"Wetland built",y:22},
    {x1:"Jun 1, 2025",x2:"Apr 15, 2026",label:"Healthy lake",y:22},
  ];

  return(
    <div>
      <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:8,flexWrap:"wrap"}}>
        <span style={{fontSize:13,fontFamily:"'Fira Code',monospace",fontWeight:600,color:"#3d3529"}}>{title}</span>
        <span style={{fontSize:10,fontFamily:"'Fira Code',monospace",display:"flex",alignItems:"center",gap:4}}>
          <span style={{width:14,height:2.5,background:actualColor,borderRadius:2,display:"inline-block"}}/><span style={{color:"#999"}}>{actualLabel}</span>
        </span>
        <span style={{fontSize:10,fontFamily:"'Fira Code',monospace",display:"flex",alignItems:"center",gap:4}}>
          <span style={{width:14,height:0,borderTop:`2.5px dashed ${expectedColor}`,display:"inline-block"}}/><span style={{color:"#999"}}>{expectedLabel}</span>
        </span>
      </div>
      <svg viewBox={`0 0 ${w} ${h}`} style={{width:"100%",height:"auto",cursor:"crosshair",background:"#fdfcfa",borderRadius:8}}
        onMouseMove={e=>{const r=e.currentTarget.getBoundingClientRect();const mx=(e.clientX-r.left)/r.width*w;let cl=0,md=Infinity;aPts.forEach((q,i)=>{const d=Math.abs(q.x-mx);if(d<md){md=d;cl=i}});setHover(md<20?cl:null)}}
        onMouseLeave={()=>setHover(null)}>
        <defs>
          <linearGradient id={`ga-${title.replace(/\W/g,'')}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={actualColor} stopOpacity="0.1"/><stop offset="100%" stopColor={actualColor} stopOpacity="0.01"/></linearGradient>
          <linearGradient id={`ge-${title.replace(/\W/g,'')}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={expectedColor} stopOpacity="0.06"/><stop offset="100%" stopColor={expectedColor} stopOpacity="0.01"/></linearGradient>
        </defs>

        {/* Y grid */}
        {yTicks.map((v,i)=>{const y=toY(v);return <g key={i}><line x1={p.left} y1={y} x2={p.left+cw} y2={y} stroke="#1a1a1a" strokeOpacity="0.05" strokeDasharray="3,5"/><text x={p.left-6} y={y+3.5} textAnchor="end" fontSize="8.5" fill="#aaa" style={{fontFamily:"'Fira Code',monospace"}}>{v.toFixed(1)}</text></g>})}

        {/* X grid + labels */}
        {years.map(yr=>{const x=toX(new Date(`Jan 1, ${yr}`).getTime());if(x<p.left||x>p.left+cw)return null;return <g key={yr}><line x1={x} y1={p.top} x2={x} y2={p.top+ch} stroke="#1a1a1a" strokeOpacity="0.05"/><text x={x} y={h-10} textAnchor="middle" fontSize="9" fill="#bbb" style={{fontFamily:"'Fira Code',monospace"}}>{yr}</text></g>})}

        {/* Expected area + line */}
        <path d={mkArea(ePts)} fill={`url(#ge-${title.replace(/\W/g,'')})`}/>
        <path d={mkLine(ePts)} fill="none" stroke={expectedColor} strokeWidth="2" strokeDasharray="8,4" strokeLinecap="round" strokeLinejoin="round" opacity="0.7"/>
        {ePts.map((q,i)=><circle key={`e${i}`} cx={q.x} cy={q.y} r="3.5" fill={expectedColor} opacity="0.5"/>)}

        {/* Actual area + line */}
        <path d={mkArea(aPts)} fill={`url(#ga-${title.replace(/\W/g,'')})`}/>
        <path d={mkLine(aPts)} fill="none" stroke={actualColor} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
        {aPts.map((q,i)=><circle key={`a${i}`} cx={q.x} cy={q.y} r={hover===i?5:monthly?2.5:1.2} fill={actualColor} opacity={hover===i?1:monthly?0.5:0.25} style={{transition:"all 0.1s"}}/>)}

        {/* Phase labels along expected line */}
        {phases.map((ph,i)=>{
          const x1=toX(pD(ph.x1)),x2=toX(pD(ph.x2)),xm=(x1+x2)/2;
          return <text key={i} x={xm} y={p.top+ch+ph.y} textAnchor="middle" fontSize="8" fill={expectedColor} opacity="0.5" style={{fontFamily:"'Fira Code',monospace"}}>{ph.label}</text>;
        })}

        {/* Hover tooltip */}
        {hover!==null&&aPts[hover]&&(
          <g>
            <line x1={aPts[hover].x} y1={p.top} x2={aPts[hover].x} y2={p.top+ch} stroke={actualColor} strokeOpacity="0.15" strokeDasharray="2,2"/>
            <rect x={aPts[hover].x-55} y={aPts[hover].y-30} width="110" height="22" rx="5" fill="#fff" stroke="#ddd" strokeWidth="0.5" filter="drop-shadow(0 1px 4px rgba(0,0,0,0.06))"/>
            <text x={aPts[hover].x} y={aPts[hover].y-15} textAnchor="middle" fontSize="10" fill="#333" style={{fontFamily:"'Fira Code',monospace",fontWeight:600}}>
              {aPts[hover].v.toFixed(3)}
            </text>
          </g>
        )}
      </svg>
    </div>
  );
}

function Stat({label,value,sub,accent}){
  return(<div style={{background:"#fff",border:"1px solid #e8e5dd",borderRadius:10,padding:"14px 16px",flex:"1 1 0",minWidth:130,boxShadow:"0 1px 3px rgba(0,0,0,0.03)"}}>
    <div style={{fontSize:8,textTransform:"uppercase",letterSpacing:1.5,color:"#999",fontFamily:"'Fira Code',monospace",marginBottom:3}}>{label}</div>
    <div style={{fontSize:22,fontWeight:700,fontFamily:"'Fira Code',monospace",color:accent,lineHeight:1.1}}>{value}</div>
    <div style={{fontSize:9,color:"#b0a998",fontFamily:"'Fira Code',monospace",marginTop:2}}>{sub}</div>
  </div>);
}

